import { Injectable, NgZone } from '@angular/core';
import { Observable } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class AgentService {
  private readonly API = 'http://localhost:8080';

  constructor(private zone: NgZone) {}

  // SSE streaming via EventSource (GET /askAgent)
  askQuestion(question: string): Observable<string> {
    return new Observable(observer => {
      const url = `${this.API}/askAgent?question=${encodeURIComponent(question)}`;
      const es = new EventSource(url);

      es.onmessage = (event) => {
        this.zone.run(() => {
          // SSE data arrives as raw text chunks — just emit directly
          if (event.data) observer.next(event.data);
        });
      };

      es.addEventListener('message', (event: MessageEvent) => {
        // handled above
      });

      es.onerror = (err) => {
        this.zone.run(() => {
          es.close();
          observer.complete();
        });
      };

      // Cleanup on unsubscribe
      return () => es.close();
    });
  }

  // File upload via POST (non-streaming, returns full response)
  askWithFile(question: string, file?: File): Observable<string> {
    return new Observable(observer => {
      const formData = new FormData();
      formData.append('question', question);
      if (file) formData.append('file', file);

      fetch(`${this.API}/askAgentWithFile`, {
        method: 'POST',
        body: formData,
        headers: { Accept: 'text/event-stream' }
      }).then(async response => {
        if (!response.body) {
          observer.error('No response body');
          return;
        }

        const reader = response.body.getReader();
        const decoder = new TextDecoder();

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const raw = decoder.decode(value, { stream: true });
          // Parse SSE lines: "data: <chunk>\n\n"
          const lines = raw.split('\n');
          for (const line of lines) {
            if (line.startsWith('data:')) {
              const chunk = line.slice(5).trimStart();
              if (chunk && chunk !== '[DONE]') {
                this.zone.run(() => observer.next(chunk));
              }
            }
          }
        }

        this.zone.run(() => observer.complete());
      }).catch(err => {
        this.zone.run(() => observer.error(err));
      });
    });
  }
}
